public class BankAccount {
    private String owner;
    private double balance;

    // Full constructor: requires both fields
    public BankAccount(String owner, double initialDeposit) {
        this.owner = owner;
        // Ensure balance can't be negative at creation
        if (initialDeposit >= 0) {
            this.balance = initialDeposit;
        }
    }

    // Overloaded constructor: name only, zero balance
    public BankAccount(String owner) {
        // Call the full constructor with 0 as balance
        this(owner, 0.0);
    }

    public void printAccount() {
        System.out.println(owner + ": $" + balance);
    }
}
// Expected: new BankAccount("Alice", 500).printAccount();
// Output: Alice: $500.0
